window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science Practical>2007>1>a","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Study carefully the experimental set-ups labelled A, B and C.    What is the aim of the experiment for which the apparatus has been set up?","images":[],"marking_scheme":"The aim of the experimental setup is:    (i) To compare/determine the amount/level of the capillarity attraction of different types of soils     (ii) To compare the capillary movement of water in different soil types.","marks":"1","difficulty":"3"},{"id":"theory>Agricultural Science Practical>2007>1>b","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"List the experimental set-ups in the order in which water has risen through the soil samples, starting with the highest","images":[],"marking_scheme":"The rise in water is in the following order;    Specimen C - Highest - Sand  Specimen A - Higher - Loam  Specimen B - Lowest - clay. (Note: These levels are what may be observed within the time limit given for the experiment. If longer the levels would change.)","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>1>c","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"List six items of apparatus used in the experimental set-up.","images":[],"marking_scheme":"Apparatus used in the experimental setup:    (i) A large beaker/basin/dish/trough    (ii) Three capillary tubes/glass tubes.    (iii) Soil samples A, B, and C.    (iv) Water    (v) Cotton wool    (vi) Clamps    (vi) Retort stands.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>1>d","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Describe briefly the procedure used in setting up the experiment.","images":[],"marking_scheme":"Description of the procedure used in setting up the experiment:    (i) Take three glass tubes and plug each with cotton wool at one end.    (ii) Dry the soil samples and break up the lumps into smaller particles/or grind.    (iii) Fill each tube with equal quant\u00edties of dry samples of clayey, loamy and sandy soils.    (iv) Fix the three tubes in an upright position with clamps.    (v) Get the three glass tubes immersed in a trough of water.    (vi) Allow to stand for the required time.    (vii) Watch the upward movement of water into the soil samples and record your observation.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>1>e","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"e","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Why is there a difference in the water levels of the soil samples in the set ups labelled B and C?","images":[],"marking_scheme":"Why there is a difference in the water levels in soil samples B and C:    (i) In sample C. sand the larger particles and pore spaces allow water to rise much faster than in clay (sample B) but stop soon because of low capillary attraction.    (ii) In sample B, clay, the very fine particles and pore spaces do not allow water to penetrate and rise fast, but as the clay particles absorb water and swell, there is greater capillarity attraction which enables the level to rise up more than sand later.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>2>a","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Study the diagrams below and use them to answer questions (a) to (c).      ldentify the equipment illustrated by diagrams D, E, F, and G.","images":["data:image/jpeg;base64,"],"marking_scheme":"ldentification of equipment D to G:    D = Gunter's chain;  E = Cross staff;  F = Prismatic compass;  G = Theodolite.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>2>b","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"State the farm operation for which the equipment illustrated by diagrams D,E,F and G.","images":[],"marking_scheme":"Farm operation for which the equipment are generally used:    They are all survey equipment or used for farm surveying","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>2>c","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Enumerate two specific uses of each of the equipment illustrated by diagrams F and G.","images":[],"marking_scheme":"Use of equipment F and G:    F - Prismatic compass;    Assisting in locating baseline or places.  Taking direction with reference to the magnetic meridian.  G-Theododite:    Measuring horizontal and vertical angles.  Triangulation in chain survey of plane.  Rectangular coordinates for location of points.  Determines elevation.  Location or sighting of station.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>2>d","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"State six general ways of maintaining the equipment illustrated by diagrams F and G.","images":[],"marking_scheme":"Ways of maintaining equipment F and G:    Clean or wash and dry properly as appropriate after use.  Grease/oil the necessary metal parts.  After use, ensure that the screws, bolts, and nuts are properly secured.  Protect the equipment from getting wet particularly specimen G.  Use the equipment according to manufacturer's instructions.  After use and cleaning store in cool dry place.  Keep the prismatic compass away from the magnetic field.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>3>a","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"a","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Observe specimens H, l, J, and K carefully.    State one method of propagation of each of the specimens","images":[],"marking_scheme":"Method of propagation of the specimens:    Specimen H- stem cutting.  Specimen I- seed yam or yam seeds,  Specimen J - tuber, stem cutting/vine.  Specimen K - rhizome.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>3>b","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"b","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"State four advantages of staking the crop which specimen I is obtained.","images":[],"marking_scheme":"Advantages of staking in the production specimen I (Yam tuber):    Staking is essential for good yields.  Stakes give support to the climbing vines.   Exposes the leaves for good interception of sunshine/photosynthesis.  Minimizes damage to the vine  Creates more room for farmer to carry out cultural practices.  Good air circulation.  Permits easy movement of the farmer in the farm.  Prevents transmission of soil pathogens to leaves through rain splash.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>3>c","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"c","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Name the toxic substance present in specimen H and give two methods of reducing it","images":[],"marking_scheme":"Toxic substance present in specimen H:    HCN/Cyanogenetic glycoside/prussic acid.  Methods or reducing the toxic substance    Boiling  Sun-drying  Fermentation  Grating  Frying  Roasting  Soaking","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>3>d","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"d","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Describe the processing of specimen H into garri.","images":[],"marking_scheme":"Description of the processing of specimen H into garri:    Get raw cassava tubers.  Peel the tubers with knife  Wash the peeled tubers  Grate the peeled tubers with a grater  Put the grated cassava into sacks  Screw press or ferment the grated tubers for 3 days  Sift the fermented material  Fry the fermented material into garri  Sift the fried garri again into fine or coarse forms  Bag the garri","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>4>a","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"a","group":"","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"State a breed of specimen L which may be used for only commercial egg production.","images":[],"marking_scheme":"Breeds of Specimen L which may be used for only commercial egg production:    White Leghorm  Black leghorm  Ancona  Grey dorking  Red sussex  Minorca.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>4>b","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"b","group":"","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"How long does it take an improved specimen L from day old to reach its point of lay","images":[],"marking_scheme":"Maturity per\u00edod of specimen L from day old to point of lay is 18-20 (plus or minus one) weeks.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>4>c","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"c","group":"","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Name any four features on the head of specimen L.","images":[],"marking_scheme":"Features on the head of specimen L are:    Comb  Wattles  Nostril  Eyes  Beak  Ear lobe.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2007>4>d","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"d","group":"","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Mention three parasites and four diseases that attack specimen L","images":[],"marking_scheme":"Parasites that attack Specimen L include:    Flea  Mite  Roundworms  Ticks  Lice.  Diseases that attack specimen L are:    Typhoid  Cholera  Fowl pox  Diptheria  Newcastle  Coccidiosis  Gumboro  Aspergillosis  Chron\u00edc Respiralory Disease (CRD),  Pullorum  Marek's  Salmonellosis  Bird Flu/Avian influenza.","marks":"1","difficulty":"3"},{"id":"theory>Agricultural Science Practical>2007>4>e","subject":"Agricultural Science Practical","year":"2007","type":"Practical","sub_label":"e","group":"","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Mention two ways of controlling the parasites mentioned in 4(d) above","images":[],"marking_scheme":"Ways of controlling the mentioned parasites:    Periodic dusting or bathing of birds with recommended insecticide powder or appropriate chemical.  Dusting/spraying of chicken pen using appropriate pesticide.  Keeping chicken pens clean/farm sanitation.  Deworm with anthelmintics.  lsolation of infected birds.","marks":"1","difficulty":"2"}];